import{_ as t,a as e,b as r,c as l}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as i,o as d,c as o,a2 as h}from"./chunks/framework.DnrXFDHb.js";const q=JSON.parse('{"title":"磁力链接使用说明","description":"","frontmatter":{},"headers":[],"relativePath":"cn/Other/magnet-transfer.md","filePath":"cn/Other/magnet-transfer.md","lastUpdated":1781962217000}'),n={name:"cn/Other/magnet-transfer.md"};function p(s,a,c,b,m,u){return d(),o("div",null,[...a[0]||(a[0]=[h('<h1 id="磁力链接使用说明" tabindex="-1">磁力链接使用说明 <a class="header-anchor" href="#磁力链接使用说明" aria-label="Permalink to &quot;磁力链接使用说明&quot;">​</a></h1><p>磁力链接功能可以把磁力链接里的文件下载下来，再自动上传到你选择的云盘渠道。</p><p>它适合用来转存番剧、视频、压缩包等文件。你只需要粘贴磁力链接，系统会在后台创建下载任务，下载完成后把文件上传到图床，并在上传列表里显示最终链接。</p><p><img src="'+t+'" alt="磁力链接" loading="lazy"></p><h2 id="入口位置" tabindex="-1">入口位置 <a class="header-anchor" href="#入口位置" aria-label="Permalink to &quot;入口位置&quot;">​</a></h2><p>磁力链接使用入口在首页上传区域。</p><p>把磁力链接粘贴到输入框里，选择“转存”，然后点击上传即可。</p><p><img src="'+e+'" alt="上传番剧" loading="lazy"></p><h2 id="第一次使用前" tabindex="-1">第一次使用前 <a class="header-anchor" href="#第一次使用前" aria-label="Permalink to &quot;第一次使用前&quot;">​</a></h2><p>使用磁力链接前，需要先在后台配置好磁力转存。</p><p>常见需要准备：</p><ol><li>GitHub 账号，用来运行下载任务。</li><li>云盘上传渠道，例如 Google Drive、OneDrive 等。</li><li>要上传到的目录。</li><li>任务超时时间。</li></ol><p>配置好以后，回到首页粘贴磁力链接就可以开始转存。</p><h2 id="怎么上传磁力链接" tabindex="-1">怎么上传磁力链接 <a class="header-anchor" href="#怎么上传磁力链接" aria-label="Permalink to &quot;怎么上传磁力链接&quot;">​</a></h2><ol><li>在首页上传框里粘贴磁力链接。</li><li>确认模式选择为“转存”。</li><li>点击上传。</li><li>等待系统创建磁力任务。</li><li>任务开始后，可以在右下角的“磁力任务”浮窗里查看进度。</li></ol><p>下载和上传过程可能需要一些时间，具体速度取决于磁力资源、GitHub 运行环境和你选择的云盘渠道。</p><p><img src="'+r+'" alt="磁力链接下载中" loading="lazy"></p><h2 id="下载完成后" tabindex="-1">下载完成后 <a class="header-anchor" href="#下载完成后" aria-label="Permalink to &quot;下载完成后&quot;">​</a></h2><p>任务完成后，上传列表会显示文件名和链接。</p><p>如果转存的是视频，列表里会显示视频预览；如果是图片，会显示图片预览；其他文件会显示普通文件图标。</p><p><img src="'+l+'" alt="下载好后的视频" loading="lazy"></p><p>完成后可以直接复制：</p><table tabindex="0"><thead><tr><th>链接类型</th><th>用途</th></tr></thead><tbody><tr><td>原始链接</td><td>直接访问文件。</td></tr><tr><td>Markdown</td><td>适合粘贴到 Markdown 文章或说明里。</td></tr><tr><td>HTML</td><td>适合粘贴到网页代码里。</td></tr><tr><td>BBCode</td><td>适合支持 BBCode 的论坛。</td></tr></tbody></table><h2 id="磁力任务浮窗" tabindex="-1">磁力任务浮窗 <a class="header-anchor" href="#磁力任务浮窗" aria-label="Permalink to &quot;磁力任务浮窗&quot;">​</a></h2><p>右下角的磁力任务浮窗会显示当前任务数量、任务名称、进度和完成状态。</p><p>常见状态包括：</p><table tabindex="0"><thead><tr><th>状态</th><th>说明</th></tr></thead><tbody><tr><td>等待中</td><td>任务已经创建，正在等待运行。</td></tr><tr><td>下载中</td><td>正在下载磁力资源。</td></tr><tr><td>上传中</td><td>文件已经下载好，正在上传到云盘。</td></tr><tr><td>完成</td><td>文件已经上传成功，可以复制链接。</td></tr><tr><td>失败</td><td>任务没有成功完成，需要查看提示后重新尝试。</td></tr></tbody></table><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ul><li>磁力链接里如果包含多个文件，系统会优先显示主要完成文件。</li><li>大文件需要更长时间，建议等待任务完成后再刷新页面。</li><li>如果资源本身没有速度，任务可能会一直很慢或失败。</li><li>如果云盘账号额度不足、权限失效或目录配置错误，任务也可能失败。</li><li>视频上传完成后，页面预览可能需要稍等几秒加载。</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="粘贴磁力链接后没有开始" tabindex="-1">粘贴磁力链接后没有开始 <a class="header-anchor" href="#粘贴磁力链接后没有开始" aria-label="Permalink to &quot;粘贴磁力链接后没有开始&quot;">​</a></h3><p>先确认后台已经开启磁力转存，并且选择了可用的 GitHub 账号和云盘渠道。</p><h3 id="一直下载很慢" tabindex="-1">一直下载很慢 <a class="header-anchor" href="#一直下载很慢" aria-label="Permalink to &quot;一直下载很慢&quot;">​</a></h3><p>磁力资源速度取决于资源本身。如果资源没有可用节点，下载会很慢，甚至无法完成。</p><h3 id="上传完成后看不到预览" tabindex="-1">上传完成后看不到预览 <a class="header-anchor" href="#上传完成后看不到预览" aria-label="Permalink to &quot;上传完成后看不到预览&quot;">​</a></h3><p>先确认文件链接可以打开。视频文件有时需要等待浏览器加载一会儿，或者点击链接打开查看。</p><h3 id="任务失败怎么办" tabindex="-1">任务失败怎么办 <a class="header-anchor" href="#任务失败怎么办" aria-label="Permalink to &quot;任务失败怎么办&quot;">​</a></h3><p>可以检查磁力链接是否有效、云盘渠道是否可用、上传目录是否正确，然后重新提交任务。</p>',38)])])}const x=i(n,[["render",p]]);export{q as __pageData,x as default};
